					["alpha"] = 0,
					["x"] = 0,
					["y"] = 0,
					["colorType"] = "custom",
					["scaleFunc"] = "function(progress, startX, startY, scaleX, scaleY)\n      return startX + (progress * (scaleX - startX)), startY + (progress * (scaleY - startY))\n    end\n  ",
					["scaley"] = 1,
					["colorFunc"] = "function(progress, r1, g1, b1, a1, r2, g2, b2, a2)\n    -- print(\"Color\", r1, g1, b1, a1, r2, g2, b2, a2)\n    \n    local color = { \n        {r = 0.0, g = 1.0, b = 0.2}, --Light\n        {r = 1.0, g = 0.7, b = 0.0}, --Moderate\n        {r = 1.0, g = 0.0, b = 0.0} --Heavy\n    }\n    \n    local charges, maxCharges, start, duration, _ = GetSpellCharges(2565)\n    \n    local c = color[3]\n    \n    if (charges >= 1 and charges < 2) then\n        c = color[1];\n    elseif (charges >= 2) then\n        c = color[1]; \n    end\n    -- print(\"c\", c.r, c.g, c.b)\n    return c.r, c.g, c.b, 1\nend",
