		["装等 ItemLevel"] = {
			["outline"] = "OUTLINE",
			["xOffset"] = 0,
			["displayText"] = "%c",
			["customText"] = "function ()\n    --    local p=C_PaperDollInfo.GetInspectItemLevel('player')\n    local m=''\n    local t,c,p=GetAverageItemLevel()\n    \n    --最高装等 字体颜色\n    local col='|cFFFFFFFF'--白色\n    if aura_env.config.total then\n        if t>c then\n            col='|cFFFF0000'--红色\n        end\n    end\n    \n    if c then--当前等级\n        --取整数 Take integer\n        if aura_env.config.f then \n            c=string.format('%d',c)\n        else\n            c=string.format('%.1f',c)\n        end\n        if (GetLocale() == \"zhCN\") then\n            m=aura_env.config.textc..c\n        else\n            m=aura_env.config.texto..c\n        end        \n    end\n    \n    if aura_env.config.total then--最高装等\n        --取整数 Take integer\n        if aura_env.config.f then \n            t=string.format('%d',t)\n        else\n            t=string.format('%.1f',t)\n        end        \n        m=m..'('..col..t..'|r'..')'\n    end\n    \n    if aura_env.config.pvp then--显示PVP装等\n        --取整数 Take integer\n        if aura_env.config.f then \n            p=string.format('%d',p)\n        else\n            p=string.format('%.1f',p)\n        end\n        \n        m=m..'(PVP'..p..')'        \n    end\n    if m~='' then return m end\n    \nend",
