			["displayText"] = "%c",
			["customText"] = "function()\n    local t=GetCorruption()--腐蚀\n    local k=GetCorruptionResistance()--腐蚀抗性\n    local c--当前腐蚀\n    if t and k then \n        c=t-k\n    end\n    \n    local m\n    if c then         \n        if c>=60 then\n            c='|cFFFF00FF'..c..'|r'--紫色\n        elseif c>=40 then\n            c='|cFFFFD700'..c..'|r'--金色\n        elseif c>= 20 then\n            c='|cFF008000'..c..'|r'--绿色\n        elseif c>=1 then\n            c='|cFFFFFFFF'..c..'|r'--白色\n        end        \n        m=c\n    end\n    \n    if aura_env.config.total then\n        if m then             \n            m=m..'(|cFFFF00FF'..t..'|r|cFFFFFFFF-|r|cFF90EE90'..k..'|r)'\n        else\n            m=t..'-'..k\n        end\n    end\n    \n    --输出     \n    if m then    \n        if (GetLocale() == \"zhCN\") then\n            m=aura_env.config.textc..m\n        else\n            m=aura_env.config.texto..m\n        end\n        \n        return  m\n    end    \nend",
