			["customText"] = "function() \n    local p=''\n    local c\n    local t=GetParryChance('player')\n    if v7 then\n        if v7 > t then \n            c=\"|cFF00FF00\"\n        elseif v7 < t then\n            c=\"|cFFFF0000\"\n        else\n            c=\"|cFFFFFFFF\"\n        end \n    end\n    \n    if aura_env.config.c then\n        if aura_env.config.cc then\n            p=  string.format('%.1f%%',t)       \n        else\n            p=  string.format('%.0f%%',t)       \n        end       \n    end\n    if aura_env.config.n then\n        if aura_env.states and aura_env.states[2].parryrating then \n            if p~='' then p=p..' ' end\n            p=p.. aura_env.states[2].parryrating            \n        end \n    end\n    if aura_env.config.gai then\n        if t>v7 then\n            if p ~='' then p=p..' ' end\n            p=p..'+'..string.format('%.0f%%',t-v7)\n        elseif t<v7 then            \n            if p ~='' then p=p..' ' end\n            p=p..'-'..string.format('%.0f%%',v7-t)\n        end        \n    end\n    \n    if p~='' then\n        if c then\n            p=c..p..'|r'\n        end\n        if aura_env.config.sys then\n            p=STAT_PARRY..p\n        else            \n            if (GetLocale() == \"zhCN\") then\n                p=aura_env.config.textc..p\n            else\n                p=aura_env.config.texto..p\n            end\n        end        \n        return p\n    end\nend\n\n--[[\nfunction()\n    return format('%.0f',GetParryChance('player'))\nend\n]]",
