			["actions"] = {
				["start"] = {
					["custom"] = "local aura_env = aura_env\nlocal region = aura_env.region\nlocal target_frame = aura_env.state.dest_frame\nregion:ClearAllPoints()\nregion:SetPoint(\"BOTTOM\",target_frame,\"BOTTOM\",0,0)",
					["do_custom"] = true,
				},
				["init"] = {
					["custom"] = "local aura_env = aura_env\nlocal LGF = LibStub(\"LibGetFrame-1.0\")\n\nfunction aura_env.GetFrame(guid)\n    for unit in WA_IterateGroupMembers() do\n        if UnitGUID(unit) == guid then return LGF.GetFrame(unit) end\n    end\n    return nil\nend\n\nfunction aura_env.Throttle(amount,overhealing,limit)\n    local amount, overhealing = amount or 0, overhealing or 0\n    if amount > limit then return true else return false end\nend\n\nfunction aura_env:InBlackList(spellId,spellName)\n    local spellId = tostring(spellId)\n    local spellName = tostring(spellName)\n    return string.find(self.config.blacklist,spellId) or string.find(self.config.blacklist,spellName)\nend",
