			["customText"] = "function ()\n    if aura_env.config.effective_heal  then \n        return (aura_env.state.effective_amount == \"0\" and \"\") or aura_env.state.effective_amount\n    else\n        return aura_env.state.amount\n    end\nend\n\n\n",
