						["custom_type"] = "stateupdate",
						["debuffType"] = "HELPFUL",
						["duration"] = "1",
						["event"] = "Health",
						["unit"] = "player",
						["names"] = {
						},
						["custom"] = "function ( allstates, event, ... )\n    local aura_env = aura_env\n    local timestamp,sub_event,hideCaster,sourceGUID,sourceName,sourceFlags,sourceRaidFlags,destGUID,destName,destFlags,destRaidFlags,spellId,spellName,spellSchool,amount,overhealing,absorbed,critical = ...\n    if aura_env:InBlackList(spellId,spellName) then return false end\n    if sourceGUID ~= UnitGUID(\"player\") then return false end\n    if sub_event == \"SPELL_HEAL\" then\n        if not aura_env.config.direct_heal then return false end\n        local limit = aura_env.config.direct_heal_min\n        if not aura_env.Throttle(amount,overhealing,limit) then return false end\n    elseif sub_event == \"SPELL_PERIODIC_HEAL\" then\n        if not aura_env.config.periodic_heal then return false end\n        local limit = aura_env.config.periodic_heal_min\n        if not aura_env.Throttle(amount,overhealing,limit) then return false end\n    end\n    local effective_amount = amount and overhealing and amount - overhealing\n    local dest_frame = aura_env.GetFrame(destGUID)\n    if not dest_frame then return false end\n    local state = {\n        show = true,\n        changed = true,\n        progressType = \"timed\",\n        duration = 1,\n        expirationTime = GetTime() + 1,\n        autoHide = true,\n        dest_frame = dest_frame,\n        dest_frame_height = dest_frame:GetHeight(),\n        amount = FormatLargeNumber(amount),\n        effective_amount = FormatLargeNumber(effective_amount),\n        critical = critical\n    }\n    allstates[#allstates+1] = state\n    return true\nend",
