			["triggers"] = {
				{
					["trigger"] = {
						["type"] = "custom",
						["custom_type"] = "event",
						["debuffType"] = "HELPFUL",
						["event"] = "Health",
						["unit"] = "player",
						["subeventPrefix"] = "SPELL",
						["custom"] = "function(event, ...)\n    \n    --handles premarked mobs\n    if event == \"PLAYER_REGEN_DISABLED\" or event == \"PLAYER_REGEN_ENABLED\" then\n        aura_env.marks = {}\n        aura_env.assigned = {}\n        for i = 1,40 do\n            local premarked = \"nameplate\"..i\n            if UnitExists(premarked) and GetRaidTargetIndex(premarked) and not UnitPlayerControlled(premarked) then\n                if not aura_env.mobList[UnitGUID(premarked)] then\n                    aura_env.assigned[GetRaidTargetIndex(premarked)] = true\n                    aura_env.marks[UnitGUID(premarked)] = GetRaidTargetIndex(premarked)\n                end\n            end\n            \n        end        \n        --handles premarked players\n        for unit in WA_IterateGroupMembers() do\n            if GetRaidTargetIndex(unit) then\n                aura_env.assigned[GetRaidTargetIndex(unit)] = true\n                aura_env.marks[unit] = GetRaidTargetIndex(unit)\n            end\n        end\n    end\n    \n    \n    --mouseover functionality\n    if event == \"UPDATE_MOUSEOVER_UNIT\"  and aura_env.config.mouseover then\n        guid = UnitGUID(\"mouseover\")\n        unitid =select(6,strsplit(\"-\",guid))\n        if UnitExists(\"mouseover\") and not GetRaidTargetIndex(\"mouseover\") and not aura_env.marks[\"mouseover\"] and aura_env.mobList[unitid] and not UnitIsDead(\"mouseover\") then\n            \n            \n            --handles premarked players\n            for unit in WA_IterateGroupMembers() do\n                if GetRaidTargetIndex(unit) then\n                    aura_env.assigned[GetRaidTargetIndex(unit)] = true\n                    aura_env.marks[unit] = GetRaidTargetIndex(unit)\n                end            \n            end\n            \n            for i=1,5 do\n                if not aura_env.assigned[aura_env.order[i]] then           \n                    aura_env.marks[guid] = aura_env.order[i]\n                    aura_env.assigned[aura_env.order[i]] = true\n                    SetRaidTarget(\"mouseover\", aura_env.order[i])\n                    return false\n                end\n            end\n        end\n    end\n    \n    \n    \n    --regular marking\n    if event == \"UNIT_COMBAT\" then\n        unit = select(1, ...)\n        if UnitExists(unit) and UnitAffectingCombat(unit) and UnitCanAttack(\"player\", unit) and not GetRaidTargetIndex(unit) and not aura_env.marks[UnitGUID(unit)] and aura_env.mobList[select(6, strsplit(\"-\", UnitGUID(unit)))] then\n            for i=1,5 do\n                if not aura_env.assigned[aura_env.order[i]] then\n                    aura_env.marks[UnitGUID(unit)] = aura_env.order[i]\n                    aura_env.assigned[aura_env.order[i]] = true\n                    SetRaidTarget(unit, aura_env.order[i])\n                    return false\n                end                \n            end    \n        end\n        \n    end\n    \n    \n    \n    \n    --Frees up marks when mobs die\n    if event == \"COMBAT_LOG_EVENT_UNFILTERED\" and select(2,...) == \"UNIT_DIED\" and aura_env.marks[select(8,...)] and UnitExists(unit) then\n        a = select(1, strsplit(\"-\", UnitGUID(unit)))\n        if a~=\"player\" then\n            \n            aura_env.assigned[aura_env.marks[select(8,...)]] = false\n            aura_env.marks[select(8,...)] = nil\n        end\n    end    \nend",
