		["近爆 Crit v1"] = {
			["outline"] = "OUTLINE",
			["xOffset"] = 0,
			["displayText"] = "%c",
			["customText"] = "function()     \n    local c\n    local p=''\n    local t= GetCritChance('player')    \n    if v1 then\n        if v1 >t then \n            c=\"|cFF00FF00\"\n        elseif v1<t then\n            c=\"|cFFFF0000\"\n        else\n            c=\"|cFFFFFFFF\"\n        end\n    end\n    if aura_env.config.c then\n        if aura_env.config.cc then\n            p=  string.format('%.1f%%',t)       \n        else\n            p=  string.format('%.0f%%',t)       \n        end        \n    end\n    if aura_env.config.n then\n        if aura_env.states[2].criticalrating and aura_env.states then\n            if p ~='' then p=p..' ' end\n            p=p..aura_env.states[2].criticalrating                   \n        end\n    end\n    if aura_env.config.gai then\n        if t>v1 then\n            if p ~='' then p=p..' ' end\n            p=p..'+'..string.format('%.0f%%',t-v1)\n        elseif t<v1 then            \n            if p ~='' then p=p..' ' end\n            p=p..'-'..string.format('%.0f%%',v1-t)\n        end        \n    end\n    \n    if p~='' then\n        if c then\n            p=c..p..'|r'\n        end\n        if aura_env.config.sys then\n            p=STAT_CRITICAL_STRIKE..p\n        else            \n            if (GetLocale() == \"zhCN\") then\n                p=aura_env.config.textc..p\n            else\n                p=aura_env.config.texto..p\n            end\n        end        \n        return p\n    end\nend\n\n--[[\nfunction()\n    return format('%.0f',GetCritChance('player'))\nend\nfunction()\n    return format('%.0f',GetSpellCritChance('player'))\nend\nReturns a players critical hit chance with spells for a certain school.\n\ntheCritChance = GetSpellCritChance(school)\nschool - \n1 for Physical\n2 for Holy\n3 for Fire\n4 for Nature\n5 for Frost\n6 for Shadow\n\nfunction GetRealSpellCrit()    \n    local holySchool = 2\n    local minCrit = GetSpellCritChance(holySchool);\n    local spellCrit    \n    this.spellCrit = {}\n    this.spellCrit[holySchool] = minCrit    \n    for i=(holySchool+1), 7 do        \n        spellCrit = GetSpellCritChance(i)\n        minCrit = min(minCrit, spellCrit)\n        this.spellCrit[i] = spellCrit        \n    end    \n    minCrit = format(\"%.0f%%\", minCrit)\n    return minCrit    \nend\n]]",
