			},
			["displayText"] = "%c",
			["customText"] = "function ()\n    local t=UnitStat('player',3)    \n    if  not t then return end\n    local c\n    local p=t\n    \n    if v8 then\n        if v8 >t then \n            c=\"|cFF00FF00\"\n        elseif v8 < t then\n            c=\"|cFFFF0000\"\n        else\n            c=\"|cFFFFFFFF\"\n        end\n    end\n    \n    if aura_env.config.h then\n        if t >=1e6 then\n            p= string.format('%.2fm',t/1e6)\n        elseif t >= 1e4 and aura_env.config.w then \n            p= string.format('%.1fw',t/1e4)\n        elseif t >=1e3 then \n            p= string.format('%.1fk',t/1e3)\n        end            \n    end\n    \n    if aura_env.config.gai then\n        local gai    \n        if v8 >t then            \n            gai=v8-t\n        elseif v8 < t then           \n            gai=t-v8\n        end\n        if gai then\n            if gai >=1e6 then\n                gai= string.format('%.2fm',gai/1e6)                \n            elseif t >= 1e4 and aura_env.config.w then \n                gai= string.format('%.1fw',gai/1e4)\n            elseif t >=1e3 then \n                gai= string.format('%.1fk',gai/1e3)\n            end    \n            if v8 >t then            \n                p=p..' -'..gai\n            elseif v8 < t then           \n                gai=t-v8\n                p=p..' +'..gai\n            end\n        end        \n    end        \n    \n    \n    if p~='' then\n        if c then\n            p=c..p..'|r'\n        end        \n        if (GetLocale() == \"zhCN\") then\n            p=aura_env.config.textc..p\n        else\n            p=aura_env.config.texto..p\n        end\n        return p\n    end\nend\n\n\n\n",
