			["customText"] = "function()\n    local x = aura_env.dev\n    local vendors = {\n        { { \"触发真相\",        1, 3300,12}, { \"触发精通\", 1, 4125,15}, { \"爆击伤害\", 2, 4125,15}, { \"渠道精通\", 2, 4125,15},     { \"渠道急速\",    3, 5000,20}, { \"扭曲触须\",     3, 13200,66}, }, \n        { { \"渠道精通\", 1, 3000,10}, { \"虚空仪式\", 1, 4125,15}, { \"触发爆击\", 2, 5000,20}, { \"额外吸血\",     2, 6300,28},     { \"触发真相\",        2, 6750,30}, { \"渠道闪避\",      2, 3300,12},    { \"渠道全能\", 3, 5000,20}, },\n        { { \"无尽之星\", 1, 5000,20}, { \"受伤全能\", 1, 4125,15}, { \"须臾洞察\", 1, 4125,15}, { \"渠道爆击\", 2, 4125,15},     { \"触发急速\",     3, 7875,35}, { \"额外吸血\",     3, 9000,45},     { \"渠道闪避\",      3, 4250,16}, },\n        { { \"渠道爆击\", 1, 3000,10}, { \"额外吸血\",     1, 4250,17}, { \"渠道急速\", 2, 4125,15}, { \"暮光毁灭\", 2, 10000,50},    { \"触发精通\",     3, 7875,35}, { \"爆击伤害\", 3, 5000,20}, },\n        { { \"渠道急速\", 1, 3000,10}, { \"扭曲触须\",     1, 3000,10}, { \"触发急速\", 2, 5000,20}, { \"虚空回响\", 2, 7875,35},     { \"无尽之星\",     3, 15000,75},{ \"渠道爆击\", 3, 5000,20}, },\n        { { \"触发急速\", 1, 4125,15},    { \"渠道闪避\",     1, 2400,8}, { \"爆击伤害\", 1, 3000,10}, { \"受伤全能\", 2, 5000,20}, { \"虚空仪式\", 2, 7875,35},     { \"渠道精通\",     3, 5000,20}, { \"暮光毁灭\", 3, 15000,75}, },\n        { { \"虚空回响\", 1, 6250,25},    { \"龟裂创伤\",1, 4125,15}, { \"渠道全能\", 1, 3000,10}, { \"触发精通\", 2, 5000,20}, { \"无尽之星\", 2, 10000,50},     { \"触发爆击\",     3, 7875,35}, { \"虚空仪式\", 3, 13200,66}, },\n        { { \"暮光毁灭\", 1, 6250,25}, { \"触发爆击\", 1, 4125,15}, { \"扭曲触须\",     2, 7875,35}, { \"渠道全能\", 2, 4125,15},     { \"虚空回响\",     3, 12000,60},{ \"受伤全能\", 3, 7875,35}, },\n        \n    }\n    local firsttime = time({ year =2020, month=5, day=21, hour=7})\n    local interval = 60*60*24*7/2\n    local timeformat = \"%m月%d日%H:%M\"\n    local nowtime = math.floor((time()-firsttime) / interval)\n    local round = math.floor((time()-firsttime) /(8 * interval))\n    local tmpf = ''\n    for i,v in ipairs(vendors[((nowtime+x)%8)+1]) do\n        local tmpt = ''\n        local tmpb = ''\n        for j,k in ipairs(v) do\n            if j == 1 then tmpt = tmpt..k..' ' end\n            if j == 2 then tmpt = k..'级'..' '..tmpt end\n            if j == 3 then tmpb = tmpb..k..' ' end\n            if j == 4 then tmpb = k..'点'..' '..tmpb end\n        end\n        tmpf = tmpf..tmpt..tmpb..'\\n'\n    end\n    return tmpf\nend",
