					["custom"] = "aura_env.dev=0\naura_env.acted='false'\nlocal w = CharacterStatsPane.ItemLevelFrame.Corruption\nw:EnableMouseWheel(true)\nw:SetScript('OnMouseWheel',function(self,delta)\n        if delta == 1 then\n            WeakAuras.ScanEvents(\"Wheelup\") \n        elseif delta == -1 then\n            WeakAuras.ScanEvents(\"Wheeldown\") \n        end\nend)\nlocal SLEshown = SLE_CharacterCorruptionButton or false\nif SLEshown then\n    SLEshown:EnableMouseWheel(true)\n    SLEshown:SetScript('OnMouseWheel',function(self,delta)\n            if delta == 1 then\n                WeakAuras.ScanEvents(\"Wheelup\") \n            elseif delta == -1 then\n                WeakAuras.ScanEvents(\"Wheeldown\") \n            end\n    end)\nend",
