		["生命 Health"] = {
			["outline"] = "OUTLINE",
			["xOffset"] = 0,
			["displayText"] = "%c",
			["customText"] = "function ()\n    local c=UnitHealth(\"player\")\n    local m=UnitHealthMax('player')\n    local p\n    \n    if aura_env.config.curh then\n        p=c\n        if aura_env.config.h then\n            if p >=1e6 then\n                p= string.format('%.2fm',p/1e6)\n            elseif p >= 1e4 and aura_env.config.w then \n                p= string.format('%.1fw',p/1e4)\n            elseif p >=1e3 then \n                p= string.format('%.1fk',p/1e3)\n            end        \n        end\n    end\n    \n    if aura_env.config.c then--%\n        local pe=('%.0f%%'):format(c/m*100)\n        if p then \n            p=p..aura_env.config.de..pe\n        else\n            p=pe\n        end            \n    end\n    \n    if aura_env.config.maxh then\n        if aura_env.config.h then\n            if m >=1e6 then\n                m= string.format('%.2fm',m/1e6)\n            elseif m >= 1e4 and aura_env.config.w then \n                m= string.format('%.1fw',m/1e4)\n            elseif m >=1e3 then \n                m= string.format('%.1fk',m/1e3)\n            end        \n        end\n        if p then \n            p=p..aura_env.config.de..m\n        else\n            p=m\n        end    \n    end\n    \n    if p then\n        if (GetLocale() == \"zhCN\") then\n            p=aura_env.config.textc..p\n        else\n            p=aura_env.config.texto..p\n        end\n        return p\n    end\nend\n\n\n",
