				["main"] = {
					["scaleFunc"] = "function(progress, startX, startY, scaleX, scaleY)\n      return startX + (progress * (scaleX - startX)), startY + (progress * (scaleY - startY))\n    end\n  ",
					["scalex"] = 1,
					["colorA"] = 1,
					["colorG"] = 0.16078431372549,
					["colorR"] = 0.137254901960784,
					["duration_type"] = "seconds",
					["use_translate"] = false,
					["rotate"] = 0,
					["scaleType"] = "straightScale",
					["type"] = "custom",
					["use_color"] = true,
					["easeType"] = "none",
					["translateFunc"] = "function(progress, startX, startY, deltaX, deltaY)\n      local prog = (progress * 3.5) % 1\n      local bounce = math.ceil(progress * 3.5)\n      local bounceDistance = math.sin(prog * math.pi) * (bounce / 4)\n    return startX + (bounceDistance * deltaX), startY + (bounceDistance * deltaY)\n  end\n  ",
					["scaley"] = 1,
					["alpha"] = 0,
					["duration"] = "0.5",
					["y"] = 0,
					["colorType"] = "custom",
					["x"] = 0,
					["use_scale"] = false,
					["colorFunc"] = "function(progress, r1, g1, b1, a1, r2, g2, b2, a2)\n    --print(\"Percent\", WA_STAGGER.percent)\n    local color = { \n        {r = 0.0, g = 1.0, b = 0.2}, --Light\n        {r = 1.0, g = 0.7, b = 0.0}, --Moderate\n        {r = 1.0, g = 0.0, b = 0.0} --Heavy\n    }\n    \n    local WA_POWER = {}\n    WA_POWER.value = UnitPower('player')\n    WA_POWER.max = UnitPowerMax('player')\n    WA_POWER.percent = WA_POWER.value / WA_POWER.max\n    \n    \n    --STAGGER_YELLOW_TRANSITION = 0.3\n    if (WA_POWER.percent > 0.4 and WA_POWER.percent < 0.7) then\n        color = color[2]; --Moderate\n    elseif (WA_POWER.percent > 0.7) then\n        color =color[1]; --Heavy\n    else\n        color = color[3]; --Light\n    end\n    \n    --print(\"Color\", color.r, color.g, color.b)\n    return color.r, color.g, color.b, a1\nend",
