			["customText"] = "function()\n    local x = aura_env.dev\n    \n    local firsttime = time({ year =2020, month=5, day=21, hour=7})\n    local interval = 60*60*24*7/2\n    local timeformat = \"%m月%d日%H:%M\"\n    local nowtime = math.floor((time()-firsttime) / interval)\n    local round = math.floor((time()-firsttime) /(8 * interval))\n    local tmpf = ''\n    tmpf = tmpf .. date(timeformat , firsttime + (nowtime + x)*interval) ..'—'\n    tmpf = tmpf .. date(timeformat , firsttime + (nowtime + x + 1)*interval) .. '\\n'\n    \n    return tmpf\nend",
