			["displayText"] = "%c",
			["customText"] = "function() \n    local p,c\n    local t,pt\n    t,pt= C_PaperDollInfo.GetStaggerPercentage(\"player\")\n    if v0 then\n        if v0 > t then \n            c=\"|cFF00FF00\"\n        elseif v0<t then\n            c=\"|cFFFF0000\"\n        else\n            c=\"|cFFFFFFFF\"\n        end\n    end\n    \n    if t==pt then\n        if aura_env.config.cc then\n            p=  string.format('%.1f%%',t)       \n        else\n            p=  string.format('%.0f%%',t)       \n        end       \n    else\n        if aura_env.config.tarstagger and pt then\n            if aura_env.config.cc then\n                p=string.format('%.1f%%',t) .. '('..string.format('%.1f%%',pt)..')'                \n            else\n                p=string.format('%.0f%%',t) .. '('..string.format('%.0f%%',pt)..')'\n            end\n        else\n            if aura_env.config.cc then\n                p=  string.format('%.1f%%',t)       \n            else\n                p=  string.format('%.0f%%',t)       \n            end       \n        end        \n    end    \n    \n    if p then\n        if c then\n            p=c..p..'|r'\n        end\n        if aura_env.config.sys then\n            p=STAT_STAGGER..p\n        else            \n            if (GetLocale() == \"zhCN\") then\n                p=aura_env.config.textc..p\n            else\n                p=aura_env.config.texto..p\n            end\n        end        \n        return p\n    end\nend",
