			["customText"] = "function() \n    local p=''\n    if aura_env.config.c then\n        if aura_env.states and aura_env.states[2].avoidancepercent then \n            local t=aura_env.states[2].avoidancepercent\n            if aura_env.config.cc then\n                p=  string.format('%.1f%%',t)       \n            else\n                p=  string.format('%.0f%%',t)       \n            end      \n        end \n    end\n    if aura_env.config.n then\n        if aura_env.states and aura_env.states[2].avoidancerating then \n            if p~='' then p=p..' ' end\n            p= p..aura_env.states[2].avoidancerating\n        end \n    end\n    \n    if p~='' then\n        if c then\n            p=c..p..'|r'\n        end\n        if aura_env.config.sys then\n            p=STAT_AVOIDANCE..p\n        else            \n            if (GetLocale() == \"zhCN\") then\n                p=aura_env.config.textc..p\n            else\n                p=aura_env.config.texto..p\n            end\n        end        \n        return p\n    end\nend\n\n\n--GetAvoidance()",
