			["customText"] = "function(...)\n    local cur, ground, flight, swim = GetUnitSpeed(\"player\")\n    local b=100/BASE_MOVEMENT_SPEED\n    local me=''\n    local sp\n    \n    if IsFlying() then--飞行\n        if (GetLocale() == \"zhCN\") then\n            me=aura_env.config.text.fc\n        else\n            me=aura_env.config.text.fo\n        end\n        \n        if cur == flight or cur == 0 then                  \n            sp=  string.format(\"%.0f\",flight*b)\n            if aura_env.config.zero and cur==0 then --当不动时显示提示\n                sp=sp..'(0)'\n            end\n        else            \n            sp= string.format(\"|cFFFF0000%.0f\", cur*b)\n        end\n        \n    elseif IsSwimming() then--游泳\n        if (GetLocale() == \"zhCN\") then            \n            me=aura_env.config.text.sc\n        else\n            me=aura_env.config.text.so\n        end        \n        if cur == swim or cur == 0 then                \n            sp= string.format(\"%.0f\", swim*b)\n            if aura_env.config.zero and cur==0 then --当不动时显示提示\n                sp=sp..'(0)'\n            end\n        else             \n            sp= string.format(\"|cFFFF0000%.0f\", cur*b)\n        end        \n    else--除飞行，游泳外\n        if IsIndoors() then--室内\n            if (GetLocale() == \"zhCN\") then\n                me=aura_env.config.text.ic\n            else\n                me=aura_env.config.text.io\n            end                        \n        else--不在室内\n            if (GetLocale() == \"zhCN\") then\n                me=aura_env.config.text.gc\n            else\n                me=aura_env.config.text.go\n            end\n        end\n        if cur == ground or cur == 0 then\n            sp=  string.format(\"%.0f\", ground*b)\n            if aura_env.config.zero and cur==0 then --当不动时显示提示\n                sp=sp..'(0)'\n            end\n        else            \n            sp= string.format(\"|cFFEE8500%.0f\", cur*b)\n        end\n    end--结束飞行 游泳 其他\n    \n    local m=''--输出提示名称\n    if aura_env.config.icon then\n        m=select(6,...)\n    end\n    \n    if aura_env.config.name then--显示名字\n        m=m..GetUnitName('player',false)\n    end    \n    if aura_env.config.show then --显示提示\n        if aura_env.config.name then\n            m=m..':'\n        end        \n        m=m..me\n    end\n    \n    if m =='' then \n        return sp     \n    else\n        local col = RAID_CLASS_COLORS[select(2, UnitClass(\"player\"))].colorStr        \n        return '|c'..col..m..'|r'..sp \n    end    \nend\n\n--if (GetLocale() == \"zhCN\") then",
