		["主属性 Main v11"] = {
			["outline"] = "OUTLINE",
			["xOffset"] = 0,
			["displayText"] = "%c",
			["customText"] = "function ()    \n    local spe=select(6,GetSpecializationInfo(GetSpecialization()))\n    if not spe then return end    \n    local t, s = {'STRENGTH', 'AGILITY', nil, 'INTELLECT'},spe\n    local u=UnitStat('player', spe)\n    \n    local c\n    if v11 then\n        if v11 >u then \n            c=\"|cFF00FF00\"\n        elseif v11<u then\n            c=\"|cFFFF0000\"\n        else\n            c=\"|cFFFFFFFF\"\n        end\n    end\n    \n    if aura_env.config.h then\n        if u >=1e6 then\n            u= string.format('%.2fm',u/1e6)\n        elseif u >= 1e4 and aura_env.config.w then \n            u= string.format('%.2fw',u/1e4)\n        elseif u >=1e3 then \n            u= string.format('%.2fk',u/1e3)\n        end            \n    end\n    \n    local col = '|c'..RAID_CLASS_COLORS[select(2,UnitClass(\"player\"))].colorStr\n    \n    local m=t[s]  and (_G['SPEC_FRAME_PRIMARY_STAT_'..t[s]]) or ''\n    if col then\n        if c then\n            return col..m..'|r'..c..u..'|r'\n        else\n            return col..m..'|r'..u\n        end\n    else\n        return m..c\n    end\nend\n\n--[[\nUnitStat('player', select(6,GetSpecializationInfo(GetSpecialization())))\nlocal col = RAID_CLASS_COLORS[select(2,UnitClass(\"player\"))].colorStr\nif (GetLocale() == \"zhCN\") then\nWrapTextInColorCode(m, col)\nInCombatLockdown()\n]]",
