			["displayText"] = "%c",
			["customText"] = "function() \n    local p=''\n    local c\n    local t=GetMasteryEffect('player')        \n    if v3 then\n        if v3 > t then \n            c=\"|cFF00FF00\"\n        elseif v3<t then\n            c=\"|cFFFF0000\"\n        else\n            c=\"|cFFFFFFFF\"\n        end       \n    end\n    \n    if aura_env.config.c then        \n        if aura_env.config.cc then\n            p=  string.format('%.1f%%',t)       \n        else\n            p=  string.format('%.0f%%',t)       \n        end        \n    end\n    if aura_env.config.n then\n        if aura_env.states and aura_env.states[2].masteryrating then \n            if p~='' then p=p..' ' end            \n            p=p.. aura_env.states[2].masteryrating\n        end \n    end\n    if aura_env.config.gai then\n        if t>v3 then\n            if p ~='' then p=p..' ' end\n            p=p..'+'..string.format('%.0f%%',t-v3)\n        elseif t<v3 then            \n            if p ~='' then p=p..' ' end\n            p=p..'-'..string.format('%.0f%%',v3-t)\n        end        \n    end\n    \n    if p~='' then\n        if c then\n            p=c..p..'|r'\n        end\n        if aura_env.config.sys then\n            p=STAT_MASTERY..p\n        else            \n            if (GetLocale() == \"zhCN\") then\n                p=aura_env.config.textc..p\n            else\n                p=aura_env.config.texto..p\n            end\n        end        \n        return p\n    end\nend\n--[[\nfunction()\n    return format('%.0f',GetMasteryEffect('player'))\nend\n]]",
